// ClusterControllerServiceServer is the server API for ClusterControllerService service.
// All implementations should embed UnimplementedClusterControllerServiceServer
// for forward compatibility.
type ClusterControllerServiceServer interface {
	GetClusterInfo(context.Context, *timestamppb.Timestamp) (*ClusterInfo, error)
	CreateJoinToken(context.Context, *CreateJoinTokenRequest) (*CreateJoinTokenResponse, error)
	RequestJoin(context.Context, *RequestJoinRequest) (*RequestJoinResponse, error)
	ListJoinRequests(context.Context, *ListJoinRequestsRequest) (*ListJoinRequestsResponse, error)
	ApproveJoin(context.Context, *ApproveJoinRequest) (*ApproveJoinResponse, error)
	RejectJoin(context.Context, *RejectJoinRequest) (*RejectJoinResponse, error)
	ListNodes(context.Context, *ListNodesRequest) (*ListNodesResponse, error)
	// ResolveNode returns the minimal identity projection for a single node
	// given any of: node_id, hostname, mac, or ip. Scoped per Clause 5 — always
	// one target. Governed by projection-clauses.md (Phase 1 contract).
	ResolveNode(context.Context, *ResolveNodeRequest) (*ResolveNodeResponse, error)
	SetNodeProfiles(context.Context, *SetNodeProfilesRequest) (*SetNodeProfilesResponse, error)
	// SetStoragePolicy declares the cluster storage-durability policy. The
	// controller (owner of /globular/system/storage-policy) validates and persists
	// it through the governed owner-write path — degraded requires explicit
	// allow_degraded, never inferred from node count.
	SetStoragePolicy(context.Context, *SetStoragePolicyRequest) (*SetStoragePolicyResponse, error)
	// GetStoragePolicy returns the declared cluster storage policy (durable when
	// none declared).
	GetStoragePolicy(context.Context, *GetStoragePolicyRequest) (*GetStoragePolicyResponse, error)
	// SetNodeBootstrapPhase is called by node-agent from workflow steps to
	// update its own bootstrap phase. The controller updates in-memory node
	// state and emits lifecycle events.
	SetNodeBootstrapPhase(context.Context, *SetNodeBootstrapPhaseRequest) (*SetNodeBootstrapPhaseResponse, error)
	// EmitWorkflowEvent is called by node-agent from workflow steps to publish
	// lifecycle events (e.g. node.bootstrap.ready) through the controller.
	EmitWorkflowEvent(context.Context, *EmitWorkflowEventRequest) (*EmitWorkflowEventResponse, error)
	RemoveNode(context.Context, *RemoveNodeRequest) (*RemoveNodeResponse, error)
	GetClusterHealth(context.Context, *GetClusterHealthRequest) (*GetClusterHealthResponse, error)
	UpdateClusterNetwork(context.Context, *UpdateClusterNetworkRequest) (*UpdateClusterNetworkResponse, error)
	ReportNodeStatus(context.Context, *ReportNodeStatusRequest) (*ReportNodeStatusResponse, error)
	GetEtcdVoterEndpoints(context.Context, *GetEtcdVoterEndpointsRequest) (*GetEtcdVoterEndpointsResponse, error)
	GetJoinRequestStatus(context.Context, *GetJoinRequestStatusRequest) (*GetJoinRequestStatusResponse, error)
	UpgradeGlobular(context.Context, *UpgradeGlobularRequest) (*UpgradeGlobularResponse, error)
	CompleteOperation(context.Context, *CompleteOperationRequest) (*CompleteOperationResponse, error)
	WatchOperations(*WatchOperationsRequest, grpc.ServerStreamingServer[OperationEvent]) error
	GetClusterHealthV1(context.Context, *GetClusterHealthV1Request) (*GetClusterHealthV1Response, error)
	// Subsystem health registry: reports the health of all background goroutines
	// (leader election, reconciler, drift detector, event publisher, etc.)
	GetSubsystemHealth(context.Context, *GetControllerSubsystemHealthRequest) (*GetControllerSubsystemHealthResponse, error)
	GetNodeHealthDetailV1(context.Context, *GetNodeHealthDetailV1Request) (*GetNodeHealthDetailV1Response, error)
	// PreviewNodeProfiles computes the unit actions and config changes that WOULD result
	// from assigning the given profiles to a node, without mutating any state.
	PreviewNodeProfiles(context.Context, *PreviewNodeProfilesRequest) (*PreviewNodeProfilesResponse, error)
	// ── Desired-state management (typed, replaces ResourcesService JSON hack) ──
	GetDesiredState(context.Context, *emptypb.Empty) (*DesiredState, error)
	// ListDesiredBuildIDs returns the canonical set of artifact build_ids
	// the controller currently considers actively desired. The set is the
	// union of:
	//   - ServiceDesiredVersion.Spec.BuildID
	//   - ServiceRelease.Spec.BuildID + Status.ResolvedBuildID
	//   - InfrastructureRelease.Spec.BuildID + Status.ResolvedBuildID
	//   - ApplicationRelease.Spec.BuildID + Status.ResolvedBuildID
	//
	// (empty build_ids are skipped).
	//
	// Repository, cluster_doctor, and any other consumer that needs the
	// "which build_ids must I keep around?" answer MUST call this RPC
	// instead of scanning /globular/resources/* etcd prefixes directly.
	// Anchored by invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage:
	// the owner computes the reachability set with its in-memory contracts
	// intact; a raw etcd scan that mirrors the logic in a consumer is a
	// forbidden_fix:read_owned_etcd_prefix_directly_instead_of_calling_owner_rpc.
	ListDesiredBuildIDs(context.Context, *ListDesiredBuildIDsRequest) (*ListDesiredBuildIDsResponse, error)
	// GetRoutingRefresh returns the current routing-refresh generation
	// (the controller's leader epoch). xDS, gateway, and other
	// routing-aware components poll this RPC to detect leader changes
	// and rebuild their routing tables. Replaces the prior
	// /globular/routing/refresh-generation etcd watch in xDS —
	// anchored by invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	//
	// The handler is leader-forwarded so the returned epoch is the
	// authoritative leader's epoch (followers retain their last-known
	// value, which may be stale after a resign — only the leader
	// increments).
	//
	// Polled at ~2s cadence by xDS; the cost is negligible (one int
	// read per poll). Sub-second latency is not a hard requirement
	// (routing refresh is a rare cluster event).
	GetRoutingRefresh(context.Context, *GetRoutingRefreshRequest) (*GetRoutingRefreshResponse, error)
	// ListExternalDomains returns every external-domain spec the
	// controller's embedded domain reconciler manages, paired with the
	// current status. Replaces the prior xDS etcd scan of
	// /globular/domains/v1/* (spec) and per-domain /status reads —
	// those prefixes are owned by the controller-side domain reconciler,
	// so consumers MUST read them via this typed RPC per
	// invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	//
	// Only the fields xDS actually consumes are surfaced. Conditions,
	// CertExpiry, LastReconcile, NodeID, Zone, ProviderRef, TargetIP,
	// PublishExternal, UseWildcardCert, TTL are deliberately omitted to
	// keep the response narrow; extend the proto when a new consumer
	// arrives that needs them.
	ListExternalDomains(context.Context, *ListExternalDomainsRequest) (*ListExternalDomainsResponse, error)
	// ListServices returns the merged service-registry view used by xDS
	// to build Envoy clusters. Each entry is the per-(service, instance)
	// map produced by config.GetServicesConfigurations() — config fields
	// merged with per-node instance fields (Address, Port, State, ...).
	//
	// Encoded as a list of JSON strings because Globular service configs
	// have dynamic schemas (different services contribute different
	// keys); a typed proto message would either bloat or constrain that.
	// The cluster_controller owns /globular/services/* (writers
	// PutInstance / PutConfig in config/etcd_service_config.go), so this
	// RPC is the canonical typed boundary for consumers reading the
	// registry — anchored by
	// invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	ListServices(context.Context, *ListServicesRequest) (*ListServicesResponse, error)
	// GetIngressStatus returns the current ingress spec summary and
	// the per-node ingress status (VRRP state, has_vip, last_error,
	// …). The cluster_controller owns /globular/ingress/v1/spec
	// (ingress_spec_guard) and aggregates the per-node status reports;
	// consumers MUST call this RPC instead of reading the keys
	// directly per
	// invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	GetIngressStatus(context.Context, *GetIngressStatusRequest) (*GetIngressStatusResponse, error)
	// RequestIngressRepublish writes the republish-request signal so
	// the ingress spec guard re-emits the current spec. Replaces the
	// CLI's prior direct write to
	// /globular/ingress/v1/republish_request.
	RequestIngressRepublish(context.Context, *RequestIngressRepublishRequest) (*RequestIngressRepublishResponse, error)
	// CreateExternalDomain writes a new external-domain spec.
	// Owner-typed: the controller's domain reconciler is the writer of
	// /globular/domains/v1/{fqdn}. Consumers MUST call this RPC
	// instead of putting the JSON spec directly into etcd.
	CreateExternalDomain(context.Context, *CreateExternalDomainRequest) (*CreateExternalDomainResponse, error)
	// DeleteExternalDomain removes an external-domain spec.
	DeleteExternalDomain(context.Context, *DeleteExternalDomainRequest) (*DeleteExternalDomainResponse, error)
	// CreateDNSProvider writes a DNS-provider config (Cloudflare,
	// Route53, manual, …). Replaces the prior CLI putting raw JSON
	// into /globular/providers/v1/{name}.
	CreateDNSProvider(context.Context, *CreateDNSProviderRequest) (*CreateDNSProviderResponse, error)
	// ListDNSProviders returns every configured DNS provider with its
	// type, zone, default TTL, and the count (not values) of credential
	// keys held server-side. Replaces the prior CLI etcd prefix scan.
	ListDNSProviders(context.Context, *ListDNSProvidersRequest) (*ListDNSProvidersResponse, error)
	// ListServiceReleases returns every ServiceRelease object the
	// controller manages, encoded as JSON strings. cluster_doctor's
	// verification step consumes the full typed structs (resolved
	// build_id, status.nodes, required_nodes, …) that the narrow
	// GetDesiredState projection drops. Wire format is JSON per
	// release because the Go types are not yet proto-generated;
	// consumers json.Unmarshal each string into
	// cluster_controllerpb.ServiceRelease as before.
	//
	// The cluster_controller owns /globular/resources/ServiceRelease/* —
	// consumers MUST call this RPC instead of scanning etcd directly
	// per invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	ListServiceReleasesJson(context.Context, *ListServiceReleasesJsonRequest) (*ListServiceReleasesJsonResponse, error)
	// ListInfrastructureReleasesJson is the parallel RPC for
	// /globular/resources/InfrastructureRelease/*. Same wire format
	// and rationale as ListServiceReleasesJson.
	ListInfrastructureReleasesJson(context.Context, *ListInfrastructureReleasesJsonRequest) (*ListInfrastructureReleasesJsonResponse, error)
	// CleanupGhostNodePackages removes installed-package records under
	// /globular/nodes/{node_id}/packages/ for nodes that are no longer
	// members of the cluster. The controller validates that node_id is
	// genuinely absent from ListNodes before deleting — guarding
	// against accidentally wiping an active node's state — then
	// performs the cleanup as the cluster's authoritative actor
	// (cluster_controller orchestrates node lifecycle, node_agent
	// owns L3 installed state but the cleanup decision is a controller
	// concern).
	//
	// Replaces the prior globularcli cleanupGhostNodes path that
	// issued cli.Delete directly against /globular/nodes/{ghost}/packages/
	// — a cross-layer write by a non-owner that violated both
	// invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage
	// and the broader cross-owner-write principle.
	CleanupGhostNodePackages(context.Context, *CleanupGhostNodePackagesRequest) (*CleanupGhostNodePackagesResponse, error)
	// GetScyllaSchemaGuardStatus returns per-keyspace guard status
	// (current_rf, required_rf, violation, last_error). Replaces the
	// CLI's prior /globular/scylla/schema_guard/* prefix scan. The
	// schema guard runs inside cluster_controller; consumers MUST
	// call this RPC per
	// invariant:four_layer.truth_read_via_owner_rpc_not_direct_storage.
	GetScyllaSchemaGuardStatus(context.Context, *GetScyllaSchemaGuardStatusRequest) (*GetScyllaSchemaGuardStatusResponse, error)
	// RequestScyllaSchemaEnforce writes the enforce-request signal
	// that the schema guard polls. Returns the stamp timestamp so
	// consumers can poll GetScyllaSchemaGuardStatus and confirm via
	// updated_at_unix >= request_unix.
	RequestScyllaSchemaEnforce(context.Context, *RequestScyllaSchemaEnforceRequest) (*RequestScyllaSchemaEnforceResponse, error)
	UpsertDesiredService(context.Context, *UpsertDesiredServiceRequest) (*DesiredState, error)
	RemoveDesiredService(context.Context, *RemoveDesiredServiceRequest) (*DesiredState, error)
	SeedDesiredState(context.Context, *SeedDesiredStateRequest) (*DesiredState, error)
	// ── Artifact validation + dry-run ──
	ValidateArtifact(context.Context, *ValidateArtifactRequest) (*ValidationReport, error)
	PreviewDesiredServices(context.Context, *DesiredServicesDelta) (*ServiceChangePreview, error)
	// ResignLeadership causes the current leader to resign the etcd election lease,
	// allowing a different controller instance to become leader. Used by leader-aware
	// deploy workflows to safely update control-plane binaries.
	ResignLeadership(context.Context, *ResignLeadershipRequest) (*ResignLeadershipResponse, error)
	// DeployControlPlanePackage triggers a leader-aware rolling update for a
	// control-plane service. Updates followers first, transfers leadership,
	// then updates the old leader. Returns the workflow run ID on acceptance.
	DeployControlPlanePackage(context.Context, *DeployControlPlanePackageRequest) (*DeployControlPlanePackageResponse, error)
	// RequestJoinAuthorization is the v2 join path. The installer submits a join
	// token and its stable identity; the controller returns a signed JoinPlan.
	// The gateway is a courier — it MUST NOT modify the plan or assign profiles.
	RequestJoinAuthorization(context.Context, *JoinAuthorizationRequest) (*JoinAuthorizationResponse, error)
	// ── ACC (adaptive concurrency control) config ──
	// The interceptor ACC config lives at /globular/system/acc/config, owned by the
	// cluster-controller. These RPCs let the CLI (and other clients) set/reset it
	// through the owner instead of a raw etcd write (RT-2).
	SetAccConfig(context.Context, *SetAccConfigRequest) (*SetAccConfigResponse, error)
	ResetAccConfig(context.Context, *ResetAccConfigRequest) (*ResetAccConfigResponse, error)
	// ── ObjectStore topology apply ──
	// ApplyObjectStoreTopology applies a previously-planned topology proposal. It
	// replaces the etcd-mediated apply_request/apply_result handshake the CLI used
	// to drive directly: the controller (owner of objectstore desired topology)
	// loads the proposal by id, runs the full admission/validation/transition
	// contract, and returns the outcome synchronously. Leader-gated.
	ApplyObjectStoreTopology(context.Context, *ApplyObjectStoreTopologyRequest) (*ApplyObjectStoreTopologyResponse, error)
	// SanitizeObjectStorePool removes stale MinIO pool peers (IPs that no longer
	// belong to an eligible cluster node) from the controller's authoritative
	// state. The controller is the sole owner of /globular/clustercontroller/state;
	// it read-modify-writes its FULL state struct (no field loss — unlike the old
	// CLI path, which clobbered the blob down to a 4-field projection) and
	// republishes objectstore desired state canonically. dry_run computes the
	// change without applying. Leader-gated.
	SanitizeObjectStorePool(context.Context, *SanitizeObjectStorePoolRequest) (*SanitizeObjectStorePoolResponse, error)
	// ── ObjectStore disk admission + topology planning (owner writes) ──
	// The cluster-controller owns objectstore placement state (admitted disks +
	// topology proposals). These replace the CLI's direct config.SaveAdmittedDisk /
	// DeleteAdmittedDisk / SaveTopologyProposal writes (RT-2). Leader-gated.
	ApproveObjectStoreDisk(context.Context, *ApproveObjectStoreDiskRequest) (*ApproveObjectStoreDiskResponse, error)
	RejectObjectStoreDisk(context.Context, *RejectObjectStoreDiskRequest) (*RejectObjectStoreDiskResponse, error)
	PlanObjectStoreTopology(context.Context, *PlanObjectStoreTopologyRequest) (*PlanObjectStoreTopologyResponse, error)
	// ActivatePlatformRelease advances the cluster's ACTIVE platform release
	// pointer (etcd /globular/platform/active_release) to release_tag, after a
	// synchronous convergence gate: every package in the local repository BOM that
	// is installed on a node must already run the BOM version on that node (native-
	// version safe). Refuses on lagging nodes unless force=true, and on a
	// platform_release older than the current anchor unless allow_regression=true.
	// Idempotent: re-activating the current tag is a no-op. The controller writes
	// ONLY the etcd anchor here — node-local release-index.json materialization is a
	// later slice. See docs/design/platform-release-pointer-advance.md.
	ActivatePlatformRelease(context.Context, *ActivatePlatformReleaseRequest) (*ActivatePlatformReleaseResponse, error)
}

